1941: RouteConstSharedPtr VirtualHostImpl::getRouteFromRoutes(
1942:     const RouteCallback& cb, const Http::RequestHeaderMap& headers,
1943:     const StreamInfo::StreamInfo& stream_info, uint64_t random_value,
1944:     absl::Span<const RouteEntryImplBaseConstSharedPtr> routes) const {
1945:   for (auto route = routes.begin(); route != routes.end(); ++route) {
1946:     if (!headers.Path() && !(*route)->supportsPathlessHeaders()) {
1947:       continue;
1948:     }
1949: 
1950:     RouteConstSharedPtr route_entry = (*route)->matches(headers, stream_info, random_value);
1951:     if (route_entry == nullptr) {
1952:       continue;
1953:     }
1954: 
1955:     if (cb == nullptr) {
1956:       return route_entry;
1957:     }
1958: 
1959:     RouteEvalStatus eval_status = (std::next(route) == routes.end())
1960:                                       ? RouteEvalStatus::NoMoreRoutes
1961:                                       : RouteEvalStatus::HasMoreRoutes;
1962:     RouteMatchStatus match_status = cb(route_entry, eval_status);
1963:     if (match_status == RouteMatchStatus::Accept) {
1964:       return route_entry;
1965:     }
1966:     if (match_status == RouteMatchStatus::Continue &&
1967:         eval_status == RouteEvalStatus::NoMoreRoutes) {
1968:       ENVOY_LOG(debug,
1969:                 "return null when route match status is Continue but there is no more routes");
1970:       return nullptr;
1971:     }
1972:   }
1973: 
1974:   ENVOY_LOG(debug, "route was resolved but final route list did not match incoming request");
1975:   return nullptr;
1976: }
