1978: RouteConstSharedPtr VirtualHostImpl::getRouteFromEntries(const RouteCallback& cb,
1979:                                                          const Http::RequestHeaderMap& headers,
1980:                                                          const StreamInfo::StreamInfo& stream_info,
1981:                                                          uint64_t random_value) const {
1982:   // In the rare case that X-Forwarded-Proto and scheme disagree (say http URL over an HTTPS
1983:   // connection), force a redirect based on underlying protocol, rather than URL
1984:   // scheme, so don't force a redirect for a http:// url served over a TLS
1985:   // connection.
1986:   const absl::string_view scheme = headers.getForwardedProtoValue();
1987:   if (scheme.empty()) {
1988:     // No scheme header. This normally only happens when ActiveStream::decodeHeaders
1989:     // bails early (as it rejects a request), or a buggy filter removes the :scheme header.
1990:     return nullptr;
1991:   }
1992: 
1993:   // First check for ssl redirect.
1994:   if (ssl_requirements_ == SslRequirements::All && scheme != "https") {
1995:     return SSL_REDIRECT_ROUTE;
1996:   } else if (ssl_requirements_ == SslRequirements::ExternalOnly && scheme != "https" &&
1997:              !Http::HeaderUtility::isEnvoyInternalRequest(headers)) {
1998:     return SSL_REDIRECT_ROUTE;
1999:   }
2000: 
2001:   if (matcher_) {
2002:     Http::Matching::HttpMatchingDataImpl data(stream_info);
2003:     data.onRequestHeaders(headers);
2004: 
2005:     auto match = Matcher::evaluateMatch<Http::HttpMatchingData>(*matcher_, data);
2006: 
2007:     if (match.result_) {
2008:       const auto result = match.result_();
2009:       if (result->typeUrl() == RouteMatchAction::staticTypeUrl()) {
2010:         const RouteMatchAction& route_action = result->getTyped<RouteMatchAction>();
2011: 
2012:         return getRouteFromRoutes(cb, headers, stream_info, random_value, {route_action.route()});
2013:       } else if (result->typeUrl() == RouteListMatchAction::staticTypeUrl()) {
2014:         const RouteListMatchAction& action = result->getTyped<RouteListMatchAction>();
2015: 
2016:         return getRouteFromRoutes(cb, headers, stream_info, random_value, action.routes());
2017:       }
2018:       PANIC("Action in router matcher should be Route or RouteList");
2019:     }
2020: 
2021:     ENVOY_LOG(debug, "failed to match incoming request: {}", static_cast<int>(match.match_state_));
2022: 
2023:     return nullptr;
2024:   }
2025: 
2026:   // Check for a route that matches the request.
2027:   return getRouteFromRoutes(cb, headers, stream_info, random_value, routes_);
2028: }
