2030: const VirtualHostImpl* RouteMatcher::findWildcardVirtualHost(
2031:     absl::string_view host, const RouteMatcher::WildcardVirtualHosts& wildcard_virtual_hosts,
2032:     RouteMatcher::SubstringFunction substring_function) const {
2033:   // We do a longest wildcard match against the host that's passed in
2034:   // (e.g. "foo-bar.baz.com" should match "*-bar.baz.com" before matching "*.baz.com" for suffix
2035:   // wildcards). This is done by scanning the length => wildcards map looking for every wildcard
2036:   // whose size is < length.
2037:   for (const auto& iter : wildcard_virtual_hosts) {
2038:     const uint32_t wildcard_length = iter.first;
2039:     const auto& wildcard_map = iter.second;
2040:     // >= because *.foo.com shouldn't match .foo.com.
2041:     if (wildcard_length >= host.size()) {
2042:       continue;
2043:     }
2044:     const auto match = wildcard_map.find(substring_function(host, wildcard_length));
2045:     if (match != wildcard_map.end()) {
2046:       return match->second.get();
2047:     }
2048:   }
2049:   return nullptr;
2050: }
