431: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
432:   downstream_headers_ = &headers;
433: 
434:   // Extract debug configuration from filter state. This is used further along to determine whether
435:   // we should append cluster and host headers to the response, and whether to forward the request
436:   // upstream.
437:   const StreamInfo::FilterStateSharedPtr& filter_state = callbacks_->streamInfo().filterState();
438:   const DebugConfig* debug_config = filter_state->getDataReadOnly<DebugConfig>(DebugConfig::key());
