440:   // TODO: Maybe add a filter API for this.
441:   grpc_request_ = Grpc::Common::isGrpcRequestHeaders(headers);
442:   exclude_http_code_stats_ = grpc_request_ && config_->suppress_grpc_request_failure_code_stats_;
443: 
444:   // Only increment rq total stat if we actually decode headers here. This does not count requests
445:   // that get handled by earlier filters.
446:   stats_.rq_total_.inc();
