491:   // A route entry matches for the request.
492:   route_entry_ = route_->routeEntry();
493:   // If there's a route specific limit and it's smaller than general downstream
494:   // limits, apply the new cap.
495:   retry_shadow_buffer_limit_ =
496:       std::min(retry_shadow_buffer_limit_, route_entry_->retryShadowBufferLimit());
497:   if (debug_config && debug_config->append_cluster_) {
