507:     stats_.no_cluster_.inc();
508:     ENVOY_STREAM_LOG(debug, "unknown cluster '{}'", *callbacks_, route_entry_->clusterName());
509: 
510:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoClusterFound);
511:     callbacks_->sendLocalReply(route_entry_->clusterNotFoundResponseCode(), "", modify_headers,
512:                                absl::nullopt,
513:                                StreamInfo::ResponseCodeDetails::get().ClusterNotFound);
514:     return Http::FilterHeadersStatus::StopIteration;
515:   }
516:   cluster_ = cluster->info();
517: 
518:   // Set up stat prefixes, etc.
519:   request_vcluster_ = route_entry_->virtualCluster(headers);
520:   if (request_vcluster_ != nullptr) {
521:     callbacks_->streamInfo().setVirtualClusterName(request_vcluster_->name());
522:   }
523:   route_stats_context_ = route_entry_->routeStatsContext();
524:   ENVOY_STREAM_LOG(debug, "cluster '{}' match for URL '{}'", *callbacks_,
525:                    route_entry_->clusterName(), headers.getPathValue());
526: 
527:   if (config_->strict_check_headers_ != nullptr) {
528:     for (const auto& header : *config_->strict_check_headers_) {
529:       const auto res = FilterUtility::StrictHeaderChecker::checkHeader(headers, header);
530:       if (!res.valid_) {
531:         callbacks_->streamInfo().setResponseFlag(
532:             StreamInfo::CoreResponseFlag::InvalidEnvoyRequestHeaders);
533:         const std::string body = fmt::format("invalid header '{}' with value '{}'",
534:                                              std::string(res.entry_->key().getStringView()),
535:                                              std::string(res.entry_->value().getStringView()));
536:         const std::string details =
537:             absl::StrCat(StreamInfo::ResponseCodeDetails::get().InvalidEnvoyRequestHeaders, "{",
538:                          StringUtil::replaceAllEmptySpace(res.entry_->key().getStringView()), "}");
539:         callbacks_->sendLocalReply(Http::Code::BadRequest, body, nullptr, absl::nullopt, details);
540:         return Http::FilterHeadersStatus::StopIteration;
541:       }
542:     }
543:   }
544: 
545:   const Http::HeaderEntry* request_alt_name = headers.EnvoyUpstreamAltStatName();
546:   if (request_alt_name) {
547:     alt_stat_prefix_ = std::make_unique<Stats::StatNameDynamicStorage>(
548:         request_alt_name->value().getStringView(), config_->scope_.symbolTable());
549:     headers.removeEnvoyUpstreamAltStatName();
550:   }
