552:   // See if we are supposed to immediately kill some percentage of this cluster's traffic.
553:   if (cluster_->maintenanceMode()) {
554:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::UpstreamOverflow);
555:     chargeUpstreamCode(Http::Code::ServiceUnavailable, nullptr, true);
556:     callbacks_->sendLocalReply(
557:         Http::Code::ServiceUnavailable, "maintenance mode",
558:         [modify_headers, this](Http::ResponseHeaderMap& headers) {
559:           if (!config_->suppress_envoy_headers_) {
560:             headers.addReference(Http::Headers::get().EnvoyOverloaded,
561:                                  Http::Headers::get().EnvoyOverloadedValues.True);
562:           }
563:           // Note: append_cluster_info does not respect suppress_envoy_headers.
564:           modify_headers(headers);
565:         },
566:         absl::nullopt, StreamInfo::ResponseCodeDetails::get().MaintenanceMode);
567:     cluster_->trafficStats()->upstream_rq_maintenance_mode_.inc();
568:     return Http::FilterHeadersStatus::StopIteration;
569:   }
