584: 
585:     // Check whether `override_auto_sni_header` is specified.
586:     const auto override_auto_sni_header =
587:         upstream_http_protocol_options.value().override_auto_sni_header();
588:     if (!override_auto_sni_header.empty()) {
589:       // Use the header value from `override_auto_sni_header` to set the SNI value.
590:       const auto overridden_header_value = Http::HeaderUtility::getAllOfHeaderAsString(
591:           headers, Http::LowerCaseString(override_auto_sni_header));
592:       if (overridden_header_value.result().has_value() &&
593:           !overridden_header_value.result().value().empty()) {
594:         header_value = overridden_header_value.result().value();
595:       }
596:     }
597:     const auto parsed_authority = Http::Utility::parseAuthority(header_value);
598:     bool should_set_sni = !parsed_authority.is_ip_address_;
599:     // `host_` returns a string_view so doing this should be safe.
